define("local_certhistory/copy_verify_url",["core/toast","core/str"],function(Toast,Str){var init=function(){document.addEventListener("click",function(e){var btn=e.target.closest('[data-action="copy-verify-url"]');if(!btn){return;}e.preventDefault();var url=btn.dataset.url;var showToast=function(){Str.get_string("linkcopied","local_certhistory").then(function(msg){Toast.add(msg,{type:"success"});return;}).catch();};if(navigator.clipboard){navigator.clipboard.writeText(url).then(showToast).catch(function(){var ta=document.createElement("textarea");ta.value=url;ta.style.cssText="position:fixed;opacity:0";document.body.appendChild(ta);ta.select();document.execCommand("copy");document.body.removeChild(ta);showToast();});}else{var ta=document.createElement("textarea");ta.value=url;ta.style.cssText="position:fixed;opacity:0";document.body.appendChild(ta);ta.select();document.execCommand("copy");document.body.removeChild(ta);showToast();}});};return{init:init};});
